Das wäre die Implementation mit einem Ringbuffer:
// Arduino UNO Q (STM32U585, Zephyr-based core) ECG sampler with Bridge/RPC frame fetch.
//
// Collects analog samples from A0 at 200 Hz into a ring buffer and exposes
// an RPC method `ecg_get_frame` that returns the pending frame as MsgPack binary.
// Frame layout (little-endian):
// [uint8 count][uint32 t0_ms][count * (uint16 sample + uint8 dt_ms)][uint16 crc16]
// dt_ms is the delta to the previous sample timestamp, saturated at 255.
//
// On the Linux side (QRB), call:
//   frame = Bridge.call(&quot;ecg_get_frame&quot;)
//   # frame is a MsgPack bin payload; parse bytes directly.
//
// NOTE: UNO Q MCU runs ArduinoCore-zephyr. We use Zephyr k_timer for periodic ticks.
// ADC read is performed in loop() to keep the timer callback short.
// Timer programming uses atomic_t  

#include &lt;Arduino.h&gt;
#include &lt;Arduino_RouterBridge.h&gt;
#include &lt;MsgPack.h&gt;
#include &lt;zephyr/kernel.h&gt;
#include &lt;zephyr/sys/atomic.h&gt;

const uint16_t SAMPLE_INTERVAL_US = 5000;  // 5 ms -&gt; 200 Hz
const uint16_t RING_SIZE          = 200;   // max samples kept between requests (~1 s)

struct Sample {
  uint16_t value;
  uint32_t t_ms;
};

volatile Sample  ringBuf[RING_SIZE];
volatile uint16_t head       = 0;  // next write position
volatile uint16_t last_sent  = 0;  // position after last sent sample
volatile bool     overflowed = false;

// Timing / scheduling
static struct k_timer sampleTimer;
//volatile uint32_t timer_ticks = 0;
atomic_t timer_ticks = ATOMIC_INIT(0);
uint32_t sample_time_us = 0;

static void onSampleTimer(struct k_timer *timer_id) {
  (void)timer_id;
  //timer_ticks++;
  atomic_inc(&amp;timer_ticks);
}

// CRC-16/IBM (Modbus style), poly 0xA001, init 0x0000
uint16_t crc16_update(uint16_t crc, uint8_t data) {
  crc ^= data;
  for (uint8_t i = 0; i &lt; 8; i++) {
    if (crc &amp; 1) {
      crc = (crc &gt;&gt; 1) ^ 0xA001;
    } else {
      crc &gt;&gt;= 1;
    }
  }
  return crc;
}

void readADC(uint32_t t_ms);
MsgPack::bin_t&lt;uint8_t&gt; ecg_get_frame();

void setup() {
  Bridge.begin();
  Bridge.provide(&quot;ecg_get_frame&quot;, ecg_get_frame);

  // Periodic 200 Hz tick using Zephyr kernel timer
  k_timer_init(&amp;sampleTimer, onSampleTimer, nullptr);
  k_timer_start(&amp;sampleTimer,
                K_USEC(SAMPLE_INTERVAL_US),   // init time
                K_USEC(SAMPLE_INTERVAL_US));  // sample period
  sample_time_us = 0;
}

void loop() {
  // Timer callback just schedules samples; read ADC in main loop.

  //uint32_t pending_samples = 0;
  //noInterrupts();
  //pending_samples = timer_ticks;
  //timer_ticks = 0;
  //interrupts();

  uint32_t pending_samples = atomic_set(&amp;timer_ticks,0);
  if (pending_samples == 0) {
    k_sleep(K_USEC(500)); // 500 micros
    // or k_yield();
  }
  else {
    while (pending_samples &gt; 0) {
      sample_time_us += SAMPLE_INTERVAL_US;
      readADC(sample_time_us / 1000);  // store ms timestamps
      pending_samples--;
    }
  }
  // Bridge background thread handles RPC requests.
}

void readADC(uint32_t t_ms) {
  uint16_t next = head + 1;
  if (next == RING_SIZE) next = 0;

  // If the ring would overwrite unsent data, drop the oldest (move last_sent forward)
  if (next == last_sent) {
    uint16_t new_last_sent = last_sent + 1;
    if (new_last_sent == RING_SIZE) new_last_sent = 0;
    last_sent = new_last_sent;
    overflowed = true;
  }

  ringBuf[head].value = analogRead(A0);
  ringBuf[head].t_ms  = t_ms;
  head = next;
}

// Basic RPC method to get pending ECG frame as MsgPack binary.
MsgPack::bin_t&lt;uint8_t&gt; ecg_get_frame() {
  // Snapshot indices atomically
  noInterrupts();
  uint16_t tail = last_sent;
  uint16_t h    = head;
  bool ovf      = overflowed;
  overflowed    = false;
  interrupts();

  MsgPack::bin_t&lt;uint8_t&gt; out;
  uint16_t count = (h &gt;= tail) ? (h - tail) : (RING_SIZE - tail + h);
  if (count == 0) {
    return out;  // empty payload, no data
  }
  if (count &gt; 255) count = 255;  // clamp to fit in uint8 count

  // Size per sample: 2 (value) + 1 (dt_ms) = 3 bytes
  // Buffer big enough for worst-case payload: 1 + 4 + 3*255 + 2 = 772 bytes
  static uint8_t frame[800];
  size_t idx = 0;
  uint16_t crc = 0;

  frame[idx++] = static_cast&lt;uint8_t&gt;(count);
  crc = crc16_update(crc, frame[0]);

  // Frame start timestamp (t0)
  uint32_t t0 = ringBuf[tail].t_ms;
  uint8_t t0_b0 = t0 &amp; 0xFF;
  uint8_t t0_b1 = (t0 &gt;&gt; 8) &amp; 0xFF;
  uint8_t t0_b2 = (t0 &gt;&gt; 16) &amp; 0xFF;
  uint8_t t0_b3 = (t0 &gt;&gt; 24) &amp; 0xFF;
  frame[idx++] = t0_b0; crc = crc16_update(crc, t0_b0);
  frame[idx++] = t0_b1; crc = crc16_update(crc, t0_b1);
  frame[idx++] = t0_b2; crc = crc16_update(crc, t0_b2);
  frame[idx++] = t0_b3; crc = crc16_update(crc, t0_b3);

  // Send samples and delta timestamps in order from tail
  uint16_t i_idx = tail;
  uint32_t prev_t = t0;
  for (uint16_t i = 0; i &lt; count; i++) {
    if (i_idx == RING_SIZE) i_idx = 0;

    uint16_t v = ringBuf[i_idx].value;
    uint32_t t = ringBuf[i_idx].t_ms;

    uint8_t b0 = v &amp; 0xFF;
    uint8_t b1 = (v &gt;&gt; 8) &amp; 0xFF;
    frame[idx++] = b0; crc = crc16_update(crc, b0);
    frame[idx++] = b1; crc = crc16_update(crc, b1);

    uint32_t dt = t - prev_t;
    uint8_t dt8 = (i == 0) ? 0 : (dt &gt; 255 ? 255 : static_cast&lt;uint8_t&gt;(dt));
    frame[idx++] = dt8; crc = crc16_update(crc, dt8);
    prev_t = t;

    i_idx++;
  }

  // crc (little-endian)
  frame[idx++] = crc &amp; 0xFF;
  frame[idx++] = (crc &gt;&gt; 8) &amp; 0xFF;

  // Advance last_sent to h (or tail + count if clamped)
  noInterrupts();
  last_sent = (tail + count) % RING_SIZE;
  interrupts();

  // If overflow happened, optionally prepend &quot;!&quot; marker (0x21) to signal host.
  if (ovf) {
    out.push_back(0x21);
  }
  for (size_t i = 0; i &lt; idx; i++) {
    out.push_back(frame[i]);
  }
  return out;
}

Hallo,

vielen Dank für deine detaillierte Anfrage und die Bereitstellung deines Codes. Das ist ein klassisches und sehr relevantes Problem in der Echtzeit-Datenerfassung, das du hier beschreibst. Dein Ansatz, von der synchronen Einzelwertübertragung zu einer asynchronen, blockbasierten Übertragung mit einem Puffer (Buffer) zu wechseln, ist genau der richtige Weg. Er entkoppelt den zeitkritischen Abtastvorgang von der langsameren Kommunikations- und Speicherlogik.

Lassen Sie uns das Problem und die Lösung systematisch nach wissenschaftlich-technischen Prinzipien aufschlüsseln.

### 1. Problemanalyse

*   **Problem:** Die Abtastrate (Sampling Rate) ist ungleichmäßig.
*   **Ursache:** Die `loop()`-Funktion auf der MCU wird durch die blockierende Kommunikation mit der MPU (`Bridge.notify()`) verzögert. Die Dauer dieser Kommunikation ist nicht deterministisch und hängt von der Auslastung beider Prozessoren sowie des Kommunikationsbusses ab. Dies verletzt die Grundvoraussetzung für digitale Signalverarbeitung, nämlich ein konstantes Abtastintervall (Shannon-Abtasttheorem).
*   **Anforderung:** Eine konstante Abtastrate von 1000 Hz (alle 1000 µs ein Sample) muss gewährleistet werden.
*   **Lösungsansatz:** Entkopplung von Datenerfassung und Datenübertragung durch eine Puffer-Architektur. Das von dir gefundene Beispiel mit dem Ringbuffer ist eine exzellente und in der Embedded-Entwicklung etablierte Methode dafür.

### 2. Systemarchitektur und Lösungsdesign

Wir adaptieren den von dir gefundenen Ringbuffer-Ansatz für deine spezifische Anwendung mit vier EMG-Sensoren.

**Prinzip des Ringbuffers (Circular Buffer):**
Ein Ringbuffer ist eine Datenstruktur, die einen festen Speicherbereich nutzt, als wäre er zyklisch verbunden. Zwei Zeiger (`head` und `tail` oder in deinem Beispiel `head` und `last_sent`) verwalten den Puffer:
*   `head`: Zeigt auf die nächste freie Position, an der geschrieben wird (Produzent, in unserem Fall die Mess-Routine).
*   `tail` (oder `last_sent`): Zeigt auf die älteste gelesene Position (Konsument, in unserem Fall die Übertragungsfunktion).
Wenn der Produzent schneller ist als der Konsument, kann der Puffer überlaufen. Dies müssen wir erkennen und behandeln.

**Angepasste Architektur:**

1.  **MCU (C++):**
    *   Ein **Timer-Interrupt** (wie der Zephyr `k_timer` im Beispiel) sorgt für eine exakte, jitter-freie Abtastung alle 1000 µs.
    *   In der Interrupt-Service-Routine (ISR) oder einer davon getriggerten Funktion werden alle vier Sensoren ausgelesen, gefiltert und die Werte zusammen mit einem Zeitstempel in eine `struct`-Instanz geschrieben.
    *   Diese `struct` wird in den Ringbuffer geschrieben, und der `head`-Zeiger wird erhöht.
    *   Die `Bridge.provide()`-Funktion (`get_emg_data`) wird vom MPU aufgerufen. Sie liest alle neuen Daten aus dem Puffer (von `last_sent` bis `head`), serialisiert sie in ein **einziges binäres Paket** und sendet dieses zurück. Danach aktualisiert sie den `last_sent`-Zeiger.

2.  **MPU (Python):**
    *   Eine periodische Funktion (z.B. alle 100 ms) ruft `Bridge.call("get_emg_data")` auf, um einen Block an Daten anzufordern.
    *   Eine Parser-Funktion auf der Python-Seite deserialisiert das binäre Paket zurück in Zeitstempel und Sensorwerte.
    *   Die extrahierten Daten werden in einer Liste oder einem DataFrame gesammelt und können dann in eine CSV-Datei geschrieben werden.

**Vorteile dieser Architektur:**

*   **Konstante Abtastrate:** Die Abtastung ist an einen präzisen Hardware-Timer gekoppelt und wird nicht durch die langsame Bridge-Kommunikation beeinflusst.
*   **Effizienz:** Die Übertragung vieler Datenpunkte in einem einzigen Block (Bulk Transfer) ist weitaus effizienter als viele kleine Übertragungen.
*   **Datenintegrität:** Durch das Verpacken der Daten in ein definiertes binäres Format mit Zeitstempeln und optional einer Prüfsumme (CRC) wird die Datenübertragung robuster.
*   **Lösung für "mehrere Rückgabewerte":** Das Problem wird umgangen, indem alle Daten (Zeitstempel, 4 Sensorwerte, Status-Flags etc.) in einen einzigen `byte`-String serialisiert werden. Dieser einzelne String ist der Rückgabewert.

