### 3. Implementierungsvorschlag

Hier ist ein konkreter, kommentierter Code-Vorschlag, der auf deiner Anforderung und dem Ringbuffer-Beispiel aufbaut.

#### 3.1. MCU-Seite (C++)

Dieser Code ersetzt deinen bisherigen `loop()`- und Datenversand-Mechanismus.

```cpp
#if defined(ARDUINO) && ARDUINO >= 100
#include "Arduino.h"
#else
#include "WProgram.h"
#endif

#include "EMGFilters.h"
#include "Arduino_RouterBridge.h"
#include <MsgPack.h>
#include <zephyr/kernel.h>
#include <zephyr/sys/atomic.h>

// --- Konfiguration ---
#define NUM_SENSORS 4
const uint16_t SAMPLE_INTERVAL_US = 1000; // 1000 µs -> 1000 Hz
const uint16_t RING_SIZE = 256;          // Puffer für 256 Samples (~256 ms bei 1kHz)

// --- Sensor-Setup ---
int sensorPins[] = {A0, A1, A2, A3};
EMGFilters myFilters[NUM_SENSORS];
float sensorOffsets[NUM_SENSORS];
SAMPLE_FREQUENCY sampleRate = SAMPLE_FREQ_1000HZ;
NOTCH_FREQUENCY humFreq = NOTCH_FREQ_50HZ;

// --- Ringbuffer-Struktur ---
struct Sample {
    float values[NUM_SENSORS]; // Array für die 4 Sensorwerte
    uint32_t t_ms;             // Zeitstempel in Millisekunden
};

volatile Sample ringBuf[RING_SIZE];
volatile uint16_t head = 0;       // Nächste Schreibposition
volatile uint16_t last_sent = 0;  // Position nach dem letzten gesendeten Sample
volatile bool overflowed = false; // Flag für Pufferüberlauf

// --- Timer für präzise Abtastung (via Zephyr Kernel) ---
static struct k_timer sampleTimer;
atomic_t timer_ticks = ATOMIC_INIT(0); // Atomarer Zähler für anstehende Samples
uint32_t sample_time_us = 0;

// --- Funktionsprototypen ---
void readAllSensors(uint32_t t_ms);
MsgPack::bin_t<uint8_t> get_emg_frame();
void calibrateSensors();
uint16_t crc16_update(uint16_t crc, uint8_t data);


// Timer-Callback wird bei jedem Intervall aufgerufen
static void onSampleTimer(struct k_timer *timer_id) {
    (void)timer_id;
    atomic_inc(&timer_ticks); // Sicher den Zähler erhöhen
}

void setup() {
    Monitor.begin(115200);
    Monitor.println("HAWK EMG-System startet...");

    // Sensoren und Filter initialisieren
    for (int i = 0; i < NUM_SENSORS; i++) {
        pinMode(sensorPins[i], INPUT);
        myFilters[i].init(sampleRate, humFreq, true, true, true);
    }

    // Kurze Verzögerung, um der MPU Zeit zum Starten zu geben
    delay(1000); 
    Monitor.println("Kalibrierung startet...");
    calibrateSensors();
    Monitor.println("Kalibrierung abgeschlossen.");

    // Bridge initialisieren und Funktion bereitstellen
    Bridge.begin();
    Bridge.provide("get_emg_frame", get_emg_frame);

    // Zephyr Kernel Timer für 1000 Hz starten
    k_timer_init(&sampleTimer, onSampleTimer, nullptr);
    k_timer_start(&sampleTimer, K_USEC(SAMPLE_INTERVAL_US), K_USEC(SAMPLE_INTERVAL_US));
}

void loop() {
    // Holen, wie viele Samples vom Timer getriggert wurden
    uint32_t pending_samples = atomic_set(&timer_ticks, 0);

    if (pending_samples == 0) {
        // Nichts zu tun, kurz schlafen, um CPU zu schonen
        k_sleep(K_USEC(200)); 
    } else {
        // Alle anstehenden Samples verarbeiten
        while (pending_samples > 0) {
            sample_time_us += SAMPLE_INTERVAL_US;
            readAllSensors(sample_time_us / 1000); // Zeit in ms übergeben
            pending_samples--;
        }
    }
    // Die Bridge-Kommunikation läuft im Hintergrund und blockiert den Loop nicht.
}

void readAllSensors(uint32_t t_ms) {
    uint16_t next = (head + 1) % RING_SIZE;

    // Pufferüberlauf prüfen: Wenn der nächste Schreib-Index den Lese-Index einholt
    if (next == last_sent) {
        overflowed = true;
        // Ältestes Element verwerfen, indem der Lese-Zeiger verschoben wird
        last_sent = (last_sent + 1) % RING_SIZE;
    }

    ringBuf[head].t_ms = t_ms;
    for (int i = 0; i < NUM_SENSORS; i++) {
        int rawValue = analogRead(sensorPins[i]);
        float filteredValue = myFilters[i].update(rawValue);
        ringBuf[head].values[i] = filteredValue - sensorOffsets[i];
    }

    head = next;
}

// Diese Funktion wird von Python aufgerufen
MsgPack::bin_t<uint8_t> get_emg_frame() {
    // Atomarer Zugriff auf die Zeiger, um Race Conditions zu vermeiden
    noInterrupts();
    uint16_t tail = last_sent;
    uint16_t h = head;
    bool ovf = overflowed;
    overflowed = false;
    interrupts();

    MsgPack::bin_t<uint8_t> out;
    uint16_t count = (h >= tail) ? (h - tail) : (RING_SIZE - tail + h);

    if (count == 0) return out; // Kein neues Datum

    // Frame-Puffer: count (1) + t0 (4) + count * (dt(1) + 4*float(16)) + crc(2)
    static uint8_t frame[1 + 4 + RING_SIZE * (1 + sizeof(float) * NUM_SENSORS) + 2];
    size_t idx = 0;
    uint16_t crc = 0;

    // 1. Anzahl der Samples (maximal 255 pro Paket)
    uint8_t frame_count = (count > 255) ? 255 : count;
    frame[idx++] = frame_count;

    // 2. Start-Zeitstempel des ersten Samples
    uint32_t t0 = ringBuf[tail].t_ms;
    memcpy(&frame[idx], &t0, sizeof(t0));
    idx += sizeof(t0);

    // 3. Alle Samples und Delta-Zeiten
    uint32_t prev_t = t0;
    uint16_t current_idx = tail;
    for (uint16_t i = 0; i < frame_count; i++) {
        // Zeit-Delta (spart Platz)
        uint32_t dt = ringBuf[current_idx].t_ms - prev_t;
        frame[idx++] = (dt > 255) ? 255 : (uint8_t)dt;
        prev_t = ringBuf[current_idx].t_ms;

        // Die 4 Sensor-Werte (als float)
        memcpy(&frame[idx], &ringBuf[current_idx].values, sizeof(float) * NUM_SENSORS);
        idx += sizeof(float) * NUM_SENSORS;

        current_idx = (current_idx + 1) % RING_SIZE;
    }

    // 4. CRC16-Prüfsumme über die Daten berechnen
    for (size_t i = 0; i < idx; i++) {
        crc = crc16_update(crc, frame[i]);
    }
    memcpy(&frame[idx], &crc, sizeof(crc));
    idx += sizeof(crc);

    // Lesezeiger aktualisieren
    noInterrupts();
    last_sent = current_idx;
    interrupts();

    // Optional: Überlauf-Signal an den Host senden
    if (ovf) {
        out.push_back(0x21); // '!'
    }

    // Frame in den MsgPack-Container kopieren
    for (size_t i = 0; i < idx; i++) {
        out.push_back(frame[i]);
    }

    return out;
}


// --- Hilfsfunktionen (Kalibrierung & CRC) ---
void calibrateSensors() {
    const int calibrationSamples = 2000;
    long sums[NUM_SENSORS] = {0};

    for (int i = 0; i < calibrationSamples; i++) {
        for (int j = 0; j < NUM_SENSORS; j++) {
            sums[j] += myFilters[j].update(analogRead(sensorPins[j]));
        }
        delayMicroseconds(SAMPLE_INTERVAL_US);
    }

    for (int i = 0; i < NUM_SENSORS; i++) {
        sensorOffsets[i] = (float)sums[i] / calibrationSamples;
        Monitor.print("Sensor "); Monitor.print(i);
        Monitor.print(" Offset: "); Monitor.println(sensorOffsets[i]);
    }
}

// CRC-16/IBM (Modbus)
uint16_t crc16_update(uint16_t crc, uint8_t data) {
    crc ^= data;
    for (uint8_t i = 0; i < 8; i++) {
        if (crc & 1) {
            crc = (crc >> 1) ^ 0xA001;
        } else {
            crc >>= 1;
        }
    }
    return crc;
}
```

#### 3.2. MPU-Seite (Python)

Dieser Code ruft die Daten ab, parst sie und speichert sie.

```python
import time
import struct
import csv
from arduino.app_utils import App, Bridge, Leds

# Globale Liste zum Sammeln aller Messdaten
all_measurements = []
is_recording = False
current_finger_state = 0 # 0=little, 1=ring, etc.

# Paylod-Format:
# <B: count
# <I: t0_ms
# [ <B: dt_ms, <f: val1, <f: val2, <f: val3, <f: val4 ] x count
# <H: crc16
# Das '<' bedeutet Little-Endian Byte Order.
SAMPLE_FORMAT = '<Bffff' # Format für ein Sample: dt_ms und 4 floats
SAMPLE_SIZE = struct.calcsize(SAMPLE_FORMAT)

def crc16_update(crc, data):
    """CRC-16/IBM (Modbus) Berechnung in Python."""
    crc ^= data
    for _ in range(8):
        if crc & 1:
            crc = (crc >> 1) ^ 0xA001
        else:
            crc >>= 1
    return crc

def parse_emg_frame(payload: bytes):
    """
    Deserialisiert das binäre Datenpaket von der MCU.
    """
    global all_measurements

    # Prüfen, ob ein Overflow-Flag gesendet wurde
    if payload and payload[0] == 0x21: # '!'
        print("WARNUNG: MCU-Puffer ist übergelaufen! Einige Samples gingen verloren.")
        payload = payload[1:]

    if len(payload) < 7: # Mindestgröße: count(1) + t0(4) + crc(2)
        return

    # CRC-Prüfsumme verifizieren
    crc_from_mcu = struct.unpack('<H', payload[-2:])[0]
    calculated_crc = 0
    for byte in payload[:-2]:
        calculated_crc = crc16_update(calculated_crc, byte)

    if crc_from_mcu != calculated_crc:
        print(f"FEHLER: CRC-Prüfsumme stimmt nicht überein! MCU: {crc_from_mcu}, Kalkuliert: {calculated_crc}. Verwerfe Paket.")
        return

    # Daten entpacken
    try:
        count, t0_ms = struct.unpack_from('<BI', payload, 0)
        offset = 5 # Start nach count und t0

        current_time_ms = t0_ms

        for i in range(count):
            dt_ms, v1, v2, v3, v4 = struct.unpack_from(SAMPLE_FORMAT, payload, offset)
            if i > 0:
                current_time_ms += dt_ms

            all_measurements.append({
                "finger": current_finger_state,
                "timestamp_ms": current_time_ms,
                "sensor_0": v1,
                "sensor_1": v2,
                "sensor_2": v3,
                "sensor_3": v4
            })
            offset += SAMPLE_SIZE

    except struct.error as e:
        print(f"Fehler beim Entpacken der Daten: {e}")


def start_stop_recording():
    """Wird per Bridge-Button oder einer anderen Logik getriggert."""
    global is_recording, all_measurements
    is_recording = not is_recording

    if is_recording:
        print("Aufnahme gestartet...")
        all_measurements = [] # Alte Daten löschen
        Leds.set_led1_color(0, 1, 0) # Grüne LED für Aufnahme
    else:
        print("Aufnahme gestoppt. Speichere Daten...")
        Leds.set_led1_color(1, 0, 0) # Rote LED für Stopp
        save_data()
        Leds.set_led1_color(0, 0, 0) # LED aus

def save_data():
    """Speichert die gesammelten Daten in einer CSV-Datei."""
    if not all_measurements:
        print("Keine Daten zum Speichern vorhanden.")
        return

    # Dateiname z.B. messung_finger0_1678886400.csv
    filename = f"messdaten/messung_finger{current_finger_state}_{int(time.time())}.csv"

    try:
        with open(filename, 'w', newline='', encoding='utf-8') as csvfile:
            fieldnames = all_measurements[0].keys()
            writer = csv.DictWriter(csvfile, fieldnames=fieldnames)
            writer.writeheader()
            writer.writerows(all_measurements)
        print(f"Daten erfolgreich in '{filename}' gespeichert.")
    except Exception as e:
        print(f"Fehler beim Speichern der Datei: {e}")

def user_loop():
    """Hauptschleife auf der MPU-Seite."""
    if is_recording:
        try:
            # Datenblock von der MCU abholen
            frame = Bridge.call("get_emg_frame")
            if frame:
                parse_emg_frame(bytes(frame))
        except Exception as e:
            print(f"Fehler bei Bridge.call: {e}")

    time.sleep(0.1) # Alle 100ms nach neuen Daten fragen

# --- Setup ---
if __name__ == "__main__":
    # Diese Funktionen könnten z.B. an die Buttons des Arduino Portenta gebunden werden
    Bridge.provide("start_stop", start_stop_recording)
    App.run(user_loop=user_loop)

```

### 4. Zusammenfassung und nächste Schritte

1.  **Ersetzen:** Ersetze deinen MCU- und MPU-Code mit den oben genannten Vorlagen.
2.  **Anpassen:** Passe die Pin-Nummern und eventuell die `RING_SIZE` an. Eine Größe von 256 ist ein guter Startpunkt. Wenn du sehr selten Daten abholst, könntest du sie vergrößern, um Pufferüberläufe zu vermeiden.
3.  **Steuerung:** Im Python-Code habe ich die Start/Stopp-Logik der Aufnahme von der MCU entkoppelt. Du musst nun auf der Python-Seite entscheiden, wann eine Aufnahme startet und stoppt (z.B. über einen Tastendruck, eine GUI oder eine `Bridge.provide`-Funktion wie `start_stop_recording`). Die Logik zum Hochzählen der Finger (`current_finger_state`) muss ebenfalls auf der Python-Seite implementiert werden, da die MPU nun die Kontrolle über den Messablauf hat.
4.  **Testen:** Überprüfe die Ausgabe im seriellen Monitor der MCU und die Print-Ausgaben auf der MPU-Seite, insbesondere auf CRC-Fehler oder Überlauf-Warnungen.

Dieser Ansatz ist robust, skalierbar und folgt den Best Practices für die Echtzeit-Datenerfassung mit Mikrocontrollern. Ich hoffe, diese ausführliche Erklärung und die Code-Beispiele helfen dir bei der erfolgreichen Umsetzung deines Projekts an der HAWK. Bei weiteren Fragen stehe ich dir gerne zur Verfügung.
